package policy

// ValidationResult holds the result of a pod validation.
type ValidationResult struct {
	Allowed    bool
	Violations []string
}

// PolicyConfig holds configurable policy parameters.
type PolicyConfig struct {
	// RequireResourceLimits enforces that all containers have CPU and memory limits.
	RequireResourceLimits bool
	// RequireNonRoot enforces runAsNonRoot in the security context.
	RequireNonRoot bool
	// DenyPrivileged denies privileged containers.
	DenyPrivileged bool
	// DenyHostNetwork denies pods with hostNetwork enabled.
	DenyHostNetwork bool
}

// DefaultPolicyConfig returns a PolicyConfig with all policies enabled.
func DefaultPolicyConfig() PolicyConfig {
	return PolicyConfig{
		RequireResourceLimits: true,
		RequireNonRoot:        true,
		DenyPrivileged:        true,
		DenyHostNetwork:       true,
	}
}

package config

import (
	"os"
	"strconv"
)

// Config holds the webhook server configuration.
type Config struct {
	Port     int
	CertFile string
	KeyFile  string
}

// Load reads configuration from environment variables.
func Load() (*Config, error) {
	port := 8443
	if p := os.Getenv("WEBHOOK_PORT"); p != "" {
		var err error
		port, err = strconv.Atoi(p)
		if err != nil {
			return nil, err
		}
	}

	certFile := os.Getenv("TLS_CERT_FILE")
	if certFile == "" {
		certFile = "/etc/webhook/certs/tls.crt"
	}

	keyFile := os.Getenv("TLS_KEY_FILE")
	if keyFile == "" {
		keyFile = "/etc/webhook/certs/tls.key"
	}

	return &Config{
		Port:     port,
		CertFile: certFile,
		KeyFile:  keyFile,
	}, nil
}

