package policy

import (
	"fmt"

	corev1 "k8s.io/api/core/v1"
)

// ValidatePod enforces the security policies on a pod.
func ValidatePod(pod *corev1.Pod, config PolicyConfig) *ValidationResult {
	violations := []string{}

	// Check for privileged containers
	if config.DenyPrivileged {
		violations = append(violations, checkPrivilegedContainers(pod, false)...)
	}

	// Check for host network access
	if config.DenyHostNetwork {
		if pod.Spec.HostNetwork {
			violations = append(violations, fmt.Sprintf("Pod %s/%s: hostNetwork is not allowed", pod.Namespace, pod.Name))
		}
	}

	// Check for required resource limits
	if config.RequireResourceLimits {
		violations = append(violations, checkResourceLimits(pod, false)...)
	}

	// Check security context constraints
	if config.RequireNonRoot {
		violations = append(violations, checkRunAsNonRoot(pod, false)...)
		violations = append(violations, checkPrivilegeEscalation(pod, false)...)
	}

	if len(violations) > 0 {
		return &ValidationResult{
			Allowed:    false,
			Violations: violations,
		}
	}

	return &ValidationResult{
		Allowed:    true,
		Violations: nil,
	}
}

// checkPrivilegedContainers checks if any container or init container is privileged.
func checkPrivilegedContainers(pod *corev1.Pod, isInitContainer bool) []string {
	violations := []string{}

	for i := range pod.Spec.Containers {
		container := &pod.Spec.Containers[i]
		if isPrivilegedContainer(container) {
			name := container.Name
			if isInitContainer {
				name = "InitContainer " + name
			}
			violations = append(violations, fmt.Sprintf("Pod %s/%s: %s is privileged", pod.Namespace, pod.Name, name))
		}
	}

	return violations
}

// checkResourceLimits checks if all containers have required CPU and memory limits.
func checkResourceLimits(pod *corev1.Pod, isInitContainer bool) []string {
	violations := []string{}

	for i := range pod.Spec.Containers {
		container := &pod.Spec.Containers[i]
		if isInitContainer {
			continue // Resource limits for init containers are optional
		}

		name := container.Name
		if isInitContainer {
			name = "InitContainer " + name
		}
		err := verifyResourceLimits(container)
		if err != nil {
			violations = append(violations, fmt.Sprintf("Pod %s/%s: %s %s", pod.Namespace, pod.Name, name, err.Error()))
		}
	}

	return violations
}

// checkRunAsNonRoot checks if runAsNonRoot is true in all containers.
func checkRunAsNonRoot(pod *corev1.Pod, isInitContainer bool) []string {
	violations := []string{}

	for i := range pod.Spec.Containers {
		container := &pod.Spec.Containers[i]
		if isPrivilegedContainer(container) {
			continue // Privileged containers bypass runAsNonRoot check
		}

		name := container.Name
		if isInitContainer {
			name = "InitContainer " + name
		}

		if container.SecurityContext != nil && container.SecurityContext.RunAsNonRoot != nil {
			if !*container.SecurityContext.RunAsNonRoot {
				violations = append(violations, fmt.Sprintf("Pod %s/%s: %s requires runAsNonRoot to be true", pod.Namespace, pod.Name, name))
			}
		} else {
			violations = append(violations, fmt.Sprintf("Pod %s/%s: %s requires runAsNonRoot to be specified", pod.Namespace, pod.Name, name))
		}
	}

	return violations
}

// checkPrivilegeEscalation checks if privilege escalation is disabled in all containers.
func checkPrivilegeEscalation(pod *corev1.Pod, isInitContainer bool) []string {
	violations := []string{}

	for i := range pod.Spec.Containers {
		container := &pod.Spec.Containers[i]
		if isPrivilegedContainer(container) {
			continue // Privileged containers bypass privilege escalation check
		}

		name := container.Name
		if isInitContainer {
			name = "InitContainer " + name
		}

		if container.SecurityContext != nil && container.SecurityContext.AllowPrivilegeEscalation != nil {
			if *container.SecurityContext.AllowPrivilegeEscalation {
				violations = append(violations, fmt.Sprintf("Pod %s/%s: %s has privilege escalation enabled", pod.Namespace, pod.Name, name))
			}
		} else {
			violations = append(violations, fmt.Sprintf("Pod %s/%s: %s requires allowPrivilegeEscalation to be explicitly set to false", pod.Namespace, pod.Name, name))
		}
	}

	return violations
}

// isPrivilegedContainer checks if a container has privileged security context.
func isPrivilegedContainer(container *corev1.Container) bool {
	if container.SecurityContext == nil {
		return false
	}
	return container.SecurityContext.Privileged != nil && *container.SecurityContext.Privileged
}

// verifyResourceLimits verifies that a container has both CPU and memory limits.
func verifyResourceLimits(container *corev1.Container) error {
	if container.Resources.Limits == nil {
		return fmt.Errorf("requires CPU and memory limits")
	}

	_, cpuOk := container.Resources.Limits[corev1.ResourceCPU]
	_, memOk := container.Resources.Limits[corev1.ResourceMemory]
	if !cpuOk || !memOk {
		if !cpuOk {
			return fmt.Errorf("requires CPU limit")
		}
		return fmt.Errorf("requires memory limit")
	}
	return nil
}

package webhook

import (
	"encoding/json"
	"fmt"
	"net/http"
	"time"

	admissionv1 "k8s.io/api/admission/v1"
	corev1 "k8s.io/api/core/v1"
	metav1 "k8s.io/apimachinery/pkg/apis/meta/v1"
	"k8s.io/klog/v2"
)

type WebhookServer struct {
	port      int
	certFile  string
	keyFile   string
	validator *PolicyValidator
}

type PolicyValidator struct {
	policyConfig PolicyConfig
}

func NewWebhookServer(port int, certFile, keyFile string, validator *PolicyValidator) *WebhookServer {
	return &WebhookServer{
		port:      port,
		certFile:  certFile,
		keyFile:   keyFile,
		validator: validator,
	}
}

func (s *WebhookServer) ServeHTTP(w http.ResponseWriter, r *http.Request) {
	// Only handle POST requests
	if r.Method != http.MethodPost {
		klog.Errorf("method not allowed: %s", r.Method)
		http.Error(w, "method not allowed", http.StatusMethodNotAllowed)
		return
	}

	// Decode the admission review
	var admissionReview admissionv1.AdmissionReview
	if err := json.NewDecoder(r.Body).Decode(&admissionReview); err != nil {
		klog.Errorf("failed to decode admission request: %v", err)
		http.Error(w, fmt.Sprintf("failed to decode admission request: %v", err), http.StatusBadRequest)
		return
	}

	// Log the admission request
	klog.V(2).Infof("received admission request for pod %s/%s", admissionReview.Request.Namespace, admissionReview.Request.Name)

	// Create admission response
	admissionResponse := &admissionv1.AdmissionResponse{
		UID: admissionReview.Request.UID,
	}

	// Validate the pod if it's a CREATE or UPDATE request
	if admissionReview.Request.Kind.Kind == "Pod" &&
		(admissionReview.Request.Operation == admissionv1.Create || admissionReview.Request.Operation == admissionv1.Update) {

		var pod corev1.Pod
		if admissionReview.Request.Object.Raw != nil {
			if err := json.Unmarshal(admissionReview.Request.Object.Raw, &pod); err != nil {
				klog.Errorf("failed to decode pod: %v", err)
				admissionResponse.Result = &metav1.Status{
					Message: fmt.Sprintf("failed to decode pod: %v", err),
				}
			}
		} else {
			// For DELETE requests, we need to validate the old object
			if admissionReview.Request.OldObject.Raw != nil {
				if err := json.Unmarshal(admissionReview.Request.OldObject.Raw, &pod); err != nil {
					klog.Errorf("failed to decode pod: %v", err)
					admissionResponse.Result = &metav1.Status{
						Message: fmt.Sprintf("failed to decode pod: %v", err),
					}
				}
			} else {
				// No object to validate, allow the request
				admissionResponse.Allowed = true
			}
		}

		// If we have a pod, validate it
		if len(admissionReview.Request.Object.Raw) > 0 || len(admissionReview.Request.OldObject.Raw) > 0 {
			var pod corev1.Pod
			if len(admissionReview.Request.Object.Raw) > 0 {
				if err := json.Unmarshal(admissionReview.Request.Object.Raw, &pod); err != nil {
					admissionResponse.Result = &metav1.Status{
						Message: fmt.Sprintf("failed to decode pod: %v", err),
					}
				} else {
					result := s.validator.ValidatePod(&pod, s.validator.policyConfig)
					admissionResponse.Allowed = result.Allowed
					if !result.Allowed && len(result.Violations) > 0 {
						admissionResponse.Result = &metav1.Status{
							Message: fmt.Sprintf("%d violation(s): %v", len(result.Violations), result.Violations),
						}
						klog.Warningf("rejected pod %s/%s: %v", pod.Namespace, pod.Name, result.Violations)
					} else {
						admissionResponse.Allowed = true
						klog.V(2).Infof("allowed pod %s/%s", pod.Namespace, pod.Name)
					}
				}
			} else if len(admissionReview.Request.OldObject.Raw) > 0 {
				// Handle UPDATE operations with old object validation
				if err := json.Unmarshal(admissionReview.Request.OldObject.Raw, &pod); err != nil {
					admissionResponse.Result = &metav1.Status{
						Message: fmt.Sprintf("failed to decode pod: %v", err),
					}
				} else {
					// For updates, validate the old pod to ensure we're not allowing policy violations
					result := s.validator.ValidatePod(&pod, s.validator.policyConfig)
					if result.Allowed {
						admissionResponse.Allowed = true
						klog.V(2).Infof("allowed update to pod %s/%s", pod.Namespace, pod.Name)
					} else {
						admissionResponse.Allowed = false
						admissionResponse.Result = &metav1.Status{
							Message: fmt.Sprintf("%d violation(s): %v", len(result.Violations), result.Violations),
						}
						klog.Warningf("rejected update to pod %s/%s: %v", pod.Namespace, pod.Name, result.Violations)
					}
				}
			}
		}
	} else {
		// Not a pod request or not CREATE/UPDATE, allow by default
		admissionResponse.Allowed = true
	}

	// Create the response admission review
	response := admissionv1.AdmissionReview{
		TypeMeta: metav1.TypeMeta{
			APIVersion: "admission.k8s.io/v1",
			Kind:       "AdmissionReview",
		},
		Response: admissionResponse,
	}

	// Serialize the response
	responseBytes, err := json.Marshal(response)
	if err != nil {
		klog.Errorf("failed to marshal response: %v", err)
		http.Error(w, "failed to marshal response", http.StatusInternalServerError)
		return
	}

	// Set content type
	w.Header().Set("Content-Type", "application/json")

	// Write the response
	if _, err := w.Write(responseBytes); err != nil {
		klog.Errorf("failed to write response: %v", err)
	}
}

package main

import (
	"fmt"
	"log"
	"net/http"
	"os"

	"github.com/terravault/terravault-admission/pkg/config"
	"github.com/terravault/terravault-admission/pkg/policy"
	"github.com/terravault/terravault-admission/pkg/webhook"
	"k8s.io/klog/v2"
)

func main() {
	// Load configuration
	cfg, err := config.Load()
	if err != nil {
		log.Fatalf("failed to load config: %v", err)
	}

	// Initialize policy validator with default configuration
	policyConfig := policy.DefaultPolicyConfig()
	validator := &webhook.PolicyValidator{
		policyConfig: policyConfig,
	}

	// Create and start webhook server
	ws := webhook.NewWebhookServer(cfg.Port, cfg.CertFile, cfg.KeyFile, validator)

	// Set up HTTP handler
	mux := http.NewServeMux()
	mux.Handle("/validate", ws)

	// Configure server
	server := &http.Server{
		Addr:    fmt.Sprintf(":%d", cfg.Port),
		Handler: mux,
	}

	klog.Infof("Starting webhook server on port %d with cert file %s", cfg.Port, cfg.CertFile)
	if err := server.ListenAndServeTLS(cfg.CertFile, cfg.KeyFile); err != nil {
		klog.Fatalf("failed to start server: %v", err)
	}
}

