package policy

import (
	"testing"

	corev1 "k8s.io/api/core/v1"
	"k8s.io/apimachinery/pkg/api/resource"
	metav1 "k8s.io/apimachinery/pkg/apis/meta/v1"
)

func TestValidatePod_NoPrivilegedContainers(t *testing.T) {
	pod := createValidPod()

	// Should be allowed
	result := ValidatePod(pod, DefaultPolicyConfig())
	if !result.Allowed {
		t.Errorf("Expected pod to be allowed, but was rejected with violations: %v", result.Violations)
	}
}

func TestValidatePod_PrivilegedContainer(t *testing.T) {
	pod := createValidPod()
	pod.Spec.Containers[0].SecurityContext = &corev1.SecurityContext{
		Privileged: boolPtr(true),
	}

	result := ValidatePod(pod, DefaultPolicyConfig())
	if result.Allowed {
		t.Errorf("Expected pod to be rejected (privileged container), but was allowed")
	}
	if len(result.Violations) == 0 {
		t.Errorf("Expected violations, but got none")
	}
}

func TestValidatePod_NoHostNetworkAccess(t *testing.T) {
	pod := createValidPod()

	// Should be allowed
	result := ValidatePod(pod, DefaultPolicyConfig())
	if !result.Allowed {
		t.Errorf("Expected pod to be allowed, but was rejected with violations: %v", result.Violations)
	}

	// Should be rejected
	pod.Spec.HostNetwork = true
	result = ValidatePod(pod, DefaultPolicyConfig())
	if result.Allowed {
		t.Errorf("Expected pod to be rejected (host network), but was allowed")
	}
	if !containsString(result.Violations, "hostNetwork is not allowed") {
		t.Errorf("Expected violation about host network, got: %v", result.Violations)
	}
}

func TestValidatePod_RequiredResourceLimits(t *testing.T) {
	pod := createValidPod()

	// Should be allowed
	result := ValidatePod(pod, DefaultPolicyConfig())
	if !result.Allowed {
		t.Errorf("Expected pod to be allowed, but was rejected with violations: %v", result.Violations)
	}

	// Should be rejected when limits are missing
	pod.Spec.Containers[0].Resources.Limits = nil
	result = ValidatePod(pod, DefaultPolicyConfig())
	if result.Allowed {
		t.Errorf("Expected pod to be rejected (no resource limits), but was allowed")
	}
	if !containsString(result.Violations, "requires CPU and memory limits") {
		t.Errorf("Expected violation about resource limits, got: %v", result.Violations)
	}

	// Should be rejected when CPU limit is missing
	pod = createValidPod()
	delete(pod.Spec.Containers[0].Resources.Limits, corev1.ResourceCPU)
	result = ValidatePod(pod, DefaultPolicyConfig())
	if result.Allowed {
		t.Errorf("Expected pod to be rejected (missing CPU limit), but was allowed")
	}

	// Should be rejected when memory limit is missing
	pod = createValidPod()
	delete(pod.Spec.Containers[0].Resources.Limits, corev1.ResourceMemory)
	result = ValidatePod(pod, DefaultPolicyConfig())
	if result.Allowed {
		t.Errorf("Expected pod to be rejected (missing memory limit), but was allowed")
	}
}

func TestValidatePod_MandatoryRunAsNonRoot(t *testing.T) {
	pod := createValidPod()

	// Should be allowed
	result := ValidatePod(pod, DefaultPolicyConfig())
	if !result.Allowed {
		t.Errorf("Expected pod to be allowed, but was rejected with violations: %v", result.Violations)
	}

	// Should be rejected when RunAsNonRoot is false
	pod.Spec.Containers[0].SecurityContext = &corev1.SecurityContext{
		RunAsNonRoot: boolPtr(false),
	}
	result = ValidatePod(pod, DefaultPolicyConfig())
	if result.Allowed {
		t.Errorf("Expected pod to be rejected (RunAsNonRoot=false), but was allowed")
	}
	if !containsString(result.Violations, "requires runAsNonRoot to be true") {
		t.Errorf("Expected violation about RunAsNonRoot, got: %v", result.Violations)
	}
}

func TestValidatePod_NoPrivilegeEscalation(t *testing.T) {
	pod := createValidPod()

	// Should be allowed
	result := ValidatePod(pod, DefaultPolicyConfig())
	if !result.Allowed {
		t.Errorf("Expected pod to be allowed, but was rejected with violations: %v", result.Violations)
	}

	// Should be rejected when AllowPrivilegeEscalation is true
	pod.Spec.Containers[0].SecurityContext = &corev1.SecurityContext{
		AllowPrivilegeEscalation: boolPtr(true),
	}
	result = ValidatePod(pod, DefaultPolicyConfig())
	if result.Allowed {
		t.Errorf("Expected pod to be rejected (privilege escalation enabled), but was allowed")
	}
	if !containsString(result.Violations, "has privilege escalation enabled") {
		t.Errorf("Expected violation about privilege escalation, got: %v", result.Violations)
	}
}

func TestValidatePod_PolicyDisabled(t *testing.T) {
	pod := createValidPod()
	pod.Spec.Containers[0].SecurityContext = &corev1.SecurityContext{
		Privileged:         boolPtr(true),
		RunAsNonRoot:       boolPtr(false),
		AllowPrivilegeEscalation: boolPtr(true),
	}

	// When privileges check is disabled, should be allowed
	config := DefaultPolicyConfig()
	config.DenyPrivileged = false
	result := ValidatePod(pod, config)
	if !result.Allowed {
		t.Errorf("Expected pod to be allowed (privilege checks disabled), but was rejected: %v", result.Violations)
	}

	// When resource limits check is disabled, missing limits should be allowed
	config = DefaultPolicyConfig()
	config.RequireResourceLimits = false
	pod = createValidPod()
	pod.Spec.Containers[0].Resources.Limits = nil
	result = ValidatePod(pod, config)
	if !result.Allowed {
		t.Errorf("Expected pod to be allowed (resource limits check disabled), but was rejected: %v", result.Violations)
	}

	// When runAsNonRoot check is disabled, should be allowed
	config = DefaultPolicyConfig()
	config.RequireNonRoot = false
	pod = createValidPod()
	pod.Spec.Containers[0].SecurityContext = &corev1.SecurityContext{
		RunAsNonRoot: boolPtr(false),
	}
	result = ValidatePod(pod, config)
	if !result.Allowed {
		t.Errorf("Expected pod to be allowed (runAsNonRoot check disabled), but was rejected: %v", result.Violations)
	}

	// When host network check is disabled, should be allowed
	config = DefaultPolicyConfig()
	config.DenyHostNetwork = false
	pod = createValidPod()
	pod.Spec.HostNetwork = true
	result = ValidatePod(pod, config)
	if !result.Allowed {
		t.Errorf("Expected pod to be allowed (host network check disabled), but was rejected: %v", result.Violations)
	}
}

func TestValidatePod_InitContainers(t *testing.T) {
	pod := createValidPod()

	// Should be allowed - init containers don't require resource limits
	pod.Spec.InitContainers = []corev1.Container{
		{
			Name:  "init",
			Image: "busybox",
		},
	}
	result := ValidatePod(pod, DefaultPolicyConfig())
	if !result.Allowed {
		t.Errorf("Expected pod to be allowed (init containers don't require limits), but was rejected: %v", result.Violations)
	}

	// Should be rejected - init containers still need security checks
	pod.Spec.InitContainers = []corev1.Container{
		{
			Name:  "init",
			Image: "busybox",
			SecurityContext: &corev1.SecurityContext{
				RunAsNonRoot: boolPtr(false),
			},
		},
	}
	result = ValidatePod(pod, DefaultPolicyConfig())
	if result.Allowed {
		t.Errorf("Expected pod to be rejected (init container violates runAsNonRoot), but was allowed")
	}
}

func TestValidatePod_MixedViolations(t *testing.T) {
	pod := createValidPod()
	pod.Spec.HostNetwork = true
	pod.Spec.Containers[0].SecurityContext = &corev1.SecurityContext{
		Privileged:              boolPtr(true),
		RunAsNonRoot:            boolPtr(false),
		AllowPrivilegeEscalation: boolPtr(true),
	}
	delete(pod.Spec.Containers[0].Resources.Limits, corev1.ResourceCPU)

	result := ValidatePod(pod, DefaultPolicyConfig())
	if result.Allowed {
		t.Errorf("Expected pod to be rejected (multiple violations), but was allowed")
	}
	if len(result.Violations) < 2 {
		t.Errorf("Expected at least 2 violations, got %d: %v", len(result.Violations), result.Violations)
	}
}

func TestValidatePod_EphemeralContainers(t *testing.T) {
	pod := createValidPod()
	pod.Spec.EphemeralContainers = []corev1.EphemeralContainer{
		{
			EphemeralContainerCommon: corev1.EphemeralContainerCommon{
				Name: "ephemeral",
				VolumeMounts: []corev1.VolumeMount{
					{
						Name: "shared",
					},
				},
			},
			Image: "busybox",
		},
	}

	// Should be rejected - ephemeral containers require validation
	result := ValidatePod(pod, DefaultPolicyConfig())
	if result.Allowed {
		t.Errorf("Expected pod to be rejected (ephemeral containers require validation), but was allowed")
	}
	if !containsString(result.Violations, "ephemeral-container") {
