	admissionv1 "k8s.io/api/admission/v1"
	corev1 "k8s.io/api/core/v1"
	metav1 "k8s.io/apimachinery/pkg/apis/meta/v1"
	"k8s.io/klog/v2"
)

type WebhookServer struct {
	port      int
	certFile  string
	keyFile   string
	validator *PolicyValidator
}

type PolicyValidator struct {
	policyConfig PolicyConfig
}

func NewWebhookServer(port int, certFile, keyFile string, validator *PolicyValidator) *WebhookServer {
	return &WebhookServer{
		port:      port,
		certFile:  certFile,
		keyFile:   keyFile,
		validator: validator,
	}
}

// DefaultPolicyConfig returns a policy config with all policies enabled
func DefaultPolicyConfig() PolicyConfig {
	return PolicyConfig{
		RequireResourceLimits: true,
		RequireNonRoot:        true,
		DenyPrivileged:        true,
		DenyHostNetwork:       true,
	}
}

func (s *WebhookServer) ServeHTTP(w http.ResponseWriter, r *http.Request) {
	// Only handle POST requests
	if r.Method != http.MethodPost {
		klog.Errorf("method not allowed: %s", r.Method)
		http.Error(w, "method not allowed", http.StatusMethodNotAllowed)
		return
	}

	// Decode the admission review
	var admissionReview admissionv1.AdmissionReview
	if err := json.NewDecoder(r.Body).Decode(&admissionReview); err != nil {
		klog.Errorf("failed to decode admission request: %v", err)
		http.Error(w, fmt.Sprintf("failed to decode admission request: %v", err), http.StatusBadRequest)
		return
	}

	// Log the admission request
	klog.V(2).Infof("received admission request for pod %s/%s", admissionReview.Request.Namespace, admissionReview.Request.Name)

	// Create admission response
	admissionResponse := &admissionv1.AdmissionResponse{
		UID: admissionReview.Request.UID,
	}

	// Validate the pod if it's a CREATE or UPDATE request
	if admissionReview.Request.Kind.Kind == "Pod" &&
		(admissionReview.Request.Operation == admissionv1.Create || admissionReview.Request.Operation == admissionv1.Update) {

		var pod corev1.Pod
		if admissionReview.Request.Object.Raw != nil {
			if err := json.Unmarshal(admissionReview.Request.Object.Raw, &pod); err != nil {
				klog.Errorf("failed to decode pod: %v", err)
				admissionResponse.Result = &metav1.Status{
					Message: fmt.Sprintf("failed to decode pod: %v", err),
				}
			}
		} else {
			// For DELETE requests, we need to validate the old object
			if admissionReview.Request.OldObject.Raw != nil {
				if err := json.Unmarshal(admissionReview.Request.OldObject.Raw, &pod); err != nil {
					klog.Errorf("failed to decode pod: %v", err)
					admissionResponse.Result = &metav1.Status{
						Message: fmt.Sprintf("failed to decode pod: %v", err),
					}
				}
			} else {
				// No object to validate, allow the request
				admissionResponse.Allowed = true
			}
		}

		// If we have a pod, validate it
		if len(admissionReview.Request.Object.Raw) > 0 || len(admissionReview.Request.OldObject.Raw) > 0 {
			var pod corev1.Pod
			if len(admissionReview.Request.Object.Raw) > 0 {
				if err := json.Unmarshal(admissionReview.Request.Object.Raw, &pod); err != nil {
					admissionResponse.Result = &metav1.Status{
						Message: fmt.Sprintf("failed to decode pod: %v", err),
					}
				} else {
					result := s.validator.ValidatePod(&pod, s.validator.policyConfig)
					admissionResponse.Allowed = result.Allowed
					if !result.Allowed && len(result.Violations) > 0 {
						admissionResponse.Result = &metav1.Status{
							Message: fmt.Sprintf("%d violation(s): %v", len(result.Violations), result.Violations),
						}
						klog.Warningf("rejected pod %s/%s: %v", pod.Namespace, pod.Name, result.Violations)
					} else {
						admissionResponse.Allowed = true
						klog.V(2).Infof("allowed pod %s/%s", pod.Namespace, pod.Name)
					}
				}
			} else if len(admissionReview.Request.OldObject.Raw) > 0 {
				// Handle UPDATE operations with old object validation
				if err := json.Unmarshal(admissionReview.Request.OldObject.Raw, &pod); err != nil {
					admissionResponse.Result = &metav1.Status{
						Message: fmt.Sprintf("failed to decode pod: %v", err),
					}
				} else {
					// For updates, validate the old pod to ensure we're not allowing policy violations
					result := s.validator.ValidatePod(&pod, s.validator.policyConfig)
					if result.Allowed {
						admissionResponse.Allowed = true
						klog.V(2).Infof("allowed update to pod %s/%s", pod.Namespace, pod.Name)
					} else {
						admissionResponse.Allowed = false
						admissionResponse.Result = &metav1.Status{
							Message: fmt.Sprintf("%d violation(s): %v", len(result.Violations), result.Violations),
						}
						klog.Warningf("rejected update to pod %s/%s: %v", pod.Namespace, pod.Name, result.Violations)
					}
				}
			}
		}
	} else {
		// Not a pod request or not CREATE/UPDATE, allow by default
		admissionResponse.Allowed = true
	}

	// Create the response admission review
	response := admissionv1.AdmissionReview{
		TypeMeta: metav1.TypeMeta{
			APIVersion: "admission.k8s.io/v1",
			Kind:       "AdmissionReview",
		},
		Response: admissionResponse,
	}

	// Serialize the response
	responseBytes, err := json.Marshal(response)
	if err != nil {
		klog.Errorf("failed to marshal response: %v", err)
		http.Error(w, "failed to marshal response", http.StatusInternalServerError)
		return
	}

	// Set content type
	w.Header().Set("Content-Type", "application/json")

	// Write the response
	if _, err := w.Write(responseBytes); err != nil {
		klog.Errorf("failed to write response: %v", err)
	}
}

